import React, { useEffect, useState } from 'react'

type HeaderProps = {
  theme: 'light' | 'dark'
  onToggleTheme: () => void
}

const Header: React.FC<HeaderProps> = ({ theme, onToggleTheme }) => {
  const [open, setOpen] = useState(false)
  const [elevated, setElevated] = useState(false)

  useEffect(() => {
    const onScroll = () => setElevated(window.scrollY > 10)
    window.addEventListener('scroll', onScroll)
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  const bg = theme === 'dark' ? 'bg-gray-900/70 text-gray-100' : 'bg-white/70 text-gray-900'
  const border = theme === 'dark' ? 'border-gray-800' : 'border-gray-200'

  const handleDownloadCV = () => {
    const content = `Shubham - Software Developer\n\nSkills: React, TypeScript, Node.js, Next.js, GraphQL, AWS\nExperience: 6+ years building scalable web apps and design systems.\nPortfolio: https://shubham.dev`;
    const blob = new Blob([content], { type: 'text/plain' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'Shubham-Resume.txt'
    document.body.appendChild(a)
    a.click()
    a.remove()
    URL.revokeObjectURL(url)
  }

  return (
    <header className={`sticky top-0 z-40 ${bg} backdrop-blur border-b ${border} ${elevated ? 'shadow-md' : ''}`}>
      <div className="max-w-6xl mx-auto px-4">
        <div className="flex items-center justify-between h-16">
          <a href="#" className="flex items-center gap-2">
            <div className="w-9 h-9 rounded-xl bg-blue-600 text-white grid place-items-center font-bold">S</div>
            <div className="font-semibold">Shubham<span className="text-blue-600">.dev</span></div>
          </a>

          <nav className="hidden md:flex items-center gap-6 text-sm">
            <a href="#about" className="text-gray-700 dark:text-gray-200 hover:text-blue-600 transition">About</a>
            <a href="#projects" className="text-gray-700 dark:text-gray-200 hover:text-blue-600 transition">Projects</a>
            <a href="#contact" className="text-gray-700 dark:text-gray-200 hover:text-blue-600 transition">Contact</a>
          </nav>

          <div className="hidden md:flex items-center gap-3">
            <button onClick={onToggleTheme} aria-label="Toggle theme" className="px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 hover:bg-gray-100 dark:hover:bg-gray-800 transition">
              {theme === 'dark' ? '☀️' : '🌙'}
            </button>
            <button onClick={handleDownloadCV} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition shadow-md">Download CV</button>
            <a href="#contact" className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition shadow-md dark:bg-white dark:text-gray-900 dark:hover:bg-gray-100">Hire Me</a>
          </div>

          <button onClick={() => setOpen(!open)} className="md:hidden px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700">
            {open ? '✕' : '☰'}
          </button>
        </div>

        {open && (
          <div className="md:hidden pb-4 flex flex-col gap-3">
            <nav className="flex flex-col gap-2 text-sm">
              <a onClick={() => setOpen(false)} href="#about" className="px-3 py-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition">About</a>
              <a onClick={() => setOpen(false)} href="#projects" className="px-3 py-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition">Projects</a>
              <a onClick={() => setOpen(false)} href="#contact" className="px-3 py-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition">Contact</a>
            </nav>
            <div className="flex items-center gap-2">
              <button onClick={onToggleTheme} className="flex-1 px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 hover:bg-gray-100 dark:hover:bg-gray-800 transition">{theme === 'dark' ? 'Light Mode' : 'Dark Mode'}</button>
              <button onClick={handleDownloadCV} className="flex-1 px-3 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Download CV</button>
            </div>
          </div>
        )}
      </div>
    </header>
  )
}

export default Header

