import React, { useEffect, useMemo, useState } from 'react'

type Project = {
  id: string
  title: string
  description: string
  image: string
  tags: string[]
  year: number
  stars: number
  link: string
}

const initialProjects: Project[] = [
  {
    id: 'p1',
    title: 'Pulse Analytics — Product Analytics Platform',
    description:
      'Full‑stack app for event tracking, cohort analysis, and retention insights. Built with React, Node.js, and ClickHouse. Achieved sub‑second dashboards with virtualized charts and caching.',
    image:
      'https://images.unsplash.com/photo-1543286386-2e659306cd6c?w=1200&q=80&auto=format&fit=crop',
    tags: ['Web', 'SaaS', 'React', 'Node.js'],
    year: 2024,
    stars: 630,
    link: '#'
  },
  {
    id: 'p2',
    title: 'Nimbus UI — Component Library',
    description:
      'A TypeScript-first React component library with theming, a11y primitives, and code‑mods. Published to NPM with Storybook docs and CI‑powered visual regression.',
    image:
      'https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=1200&q=80&auto=format&fit=crop',
    tags: ['Open Source', 'UI/UX', 'TypeScript'],
    year: 2023,
    stars: 1200,
    link: '#'
  },
  {
    id: 'p3',
    title: 'Voyager — Travel Planner App',
    description:
      'Cross‑platform trip planning with offline maps, itinerary collaboration, and smart recommendations using embeddings.',
    image:
      'https://images.unsplash.com/photo-1491553895911-0055eca6402d?w=1200&q=80&auto=format&fit=crop',
    tags: ['Mobile', 'AI/ML', 'React Native'],
    year: 2022,
    stars: 480,
    link: '#'
  },
  {
    id: 'p4',
    title: 'Helix Commerce — Headless Storefront',
    description:
      'Next.js storefront with edge caching, ISR, and GraphQL federation. 99.9% uptime and 40% LCP improvement.',
    image:
      'https://images.unsplash.com/photo-1518779578993-ec3579fee39f?w=1200&q=80&auto=format&fit=crop',
    tags: ['Web', 'Next.js', 'GraphQL'],
    year: 2023,
    stars: 820,
    link: '#'
  },
  {
    id: 'p5',
    title: 'Spectra — Realtime Dashboard',
    description:
      'WebSocket‑driven dashboards for IoT telemetry with fine‑grained permissions and audit trails. Achieved 50k msg/s ingest.',
    image:
      'https://images.unsplash.com/photo-1556157382-97eda2d62296?w=1200&q=80&auto=format&fit=crop',
    tags: ['Web', 'SaaS', 'Realtime'],
    year: 2021,
    stars: 390,
    link: '#'
  },
  {
    id: 'p6',
    title: 'Sketchflow — Design to Code',
    description:
      'Transforms design tokens to typed components and CSS vars. CLI + VSCode extension improves handoff by 5x.',
    image:
      'https://images.unsplash.com/photo-1555066931-4365d14bab8c?w=1200&q=80&auto=format&fit=crop',
    tags: ['Open Source', 'UI/UX', 'TypeScript'],
    year: 2024,
    stars: 950,
    link: '#'
  }
]

const TAGS = ['All', 'Web', 'Mobile', 'Open Source', 'AI/ML', 'UI/UX']

type SortKey = 'Newest' | 'Stars' | 'A-Z'

const ProjectList: React.FC = () => {
  const [query, setQuery] = useState('')
  const [tag, setTag] = useState<string>('All')
  const [sortBy, setSortBy] = useState<SortKey>('Newest')
  const [expanded, setExpanded] = useState<string | null>(null)
  const [favorites, setFavorites] = useState<string[]>(() => {
    if (typeof window === 'undefined') return []
    try {
      return JSON.parse(localStorage.getItem('favorites') || '[]')
    } catch {
      return []
    }
  })
  const [showFav, setShowFav] = useState(false)

  useEffect(() => {
    localStorage.setItem('favorites', JSON.stringify(favorites))
  }, [favorites])

  const filtered = useMemo(() => {
    let data = initialProjects.slice()
    if (tag !== 'All') data = data.filter((p) => p.tags.includes(tag))
    if (query.trim()) {
      const q = query.toLowerCase()
      data = data.filter((p) => p.title.toLowerCase().includes(q) || p.description.toLowerCase().includes(q) || p.tags.join(' ').toLowerCase().includes(q))
    }
    if (showFav) data = data.filter((p) => favorites.includes(p.id))
    switch (sortBy) {
      case 'Newest':
        data.sort((a, b) => b.year - a.year)
        break
      case 'Stars':
        data.sort((a, b) => b.stars - a.stars)
        break
      case 'A-Z':
        data.sort((a, b) => a.title.localeCompare(b.title))
        break
    }
    return data
  }, [query, tag, sortBy, favorites, showFav])

  const toggleFav = (id: string) => {
    setFavorites((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]))
  }

  return (
    <div>
      <div className="flex flex-col md:flex-row md:items-center gap-3 mb-6">
        <div className="flex-1 relative">
          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search projects, tags..."
            className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 outline-none focus:ring-2 focus:ring-blue-500"
          />
          {query && (
            <button onClick={() => setQuery('')} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700">✕</button>
          )}
        </div>
        <div className="flex items-center gap-2">
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value as SortKey)}
            className="px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900"
          >
            <option>Newest</option>
            <option>Stars</option>
            <option>A-Z</option>
          </select>
          <button onClick={() => setShowFav((s) => !s)} className={`px-3 py-2 rounded-lg border transition ${showFav ? 'bg-yellow-100 border-yellow-300 text-yellow-800' : 'border-gray-200 dark:border-gray-700 hover:bg-gray-100 dark:hover:bg-gray-800'}`}>
            {showFav ? '★ Favorites' : '☆ Favorites'}
          </button>
        </div>
      </div>

      <div className="flex flex-wrap gap-2 mb-6">
        {TAGS.map((t) => (
          <button
            key={t}
            onClick={() => setTag(t)}
            className={`px-3 py-1.5 rounded-full text-sm transition border ${
              tag === t
                ? 'bg-blue-600 text-white border-blue-600'
                : 'border-gray-200 dark:border-gray-700 hover:bg-gray-100 dark:hover:bg-gray-800'
            }`}
          >
            {t}
          </button>
        ))}
      </div>

      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filtered.map((p) => (
          <article key={p.id} className="rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 shadow-md overflow-hidden flex flex-col">
            <div className="relative">
              <img src={`${p.image}`} alt={p.title} className="w-full h-44 object-cover" />
              <button
                onClick={() => toggleFav(p.id)}
                className={`absolute top-3 right-3 px-2 py-1 rounded-lg text-sm shadow-md transition ${
                  favorites.includes(p.id) ? 'bg-yellow-400 text-yellow-900' : 'bg-white/90 hover:bg-white'
                }`}
                aria-label="Toggle favorite"
              >
                {favorites.includes(p.id) ? '★' : '☆'}
              </button>
            </div>
            <div className="p-5 flex-1 flex flex-col">
              <div className="flex items-start justify-between gap-3">
                <h3 className="font-semibold text-lg leading-snug">{p.title}</h3>
                <span className="px-2 py-0.5 rounded bg-gray-100 dark:bg-gray-800 text-xs">{p.year}</span>
              </div>
              <p className="text-gray-700 dark:text-gray-300 mt-2 line-clamp-3">{p.description}</p>
              <div className="mt-3 flex flex-wrap gap-2">
                {p.tags.slice(0, 3).map((t) => (
                  <span key={t} className="px-2 py-0.5 rounded-full bg-gray-100 dark:bg-gray-800 text-xs text-gray-700 dark:text-gray-300">{t}</span>
                ))}
                <span className="ml-auto text-sm text-gray-600 dark:text-gray-400">★ {p.stars}</span>
              </div>

              {expanded === p.id && (
                <div className="mt-4 text-sm text-gray-700 dark:text-gray-300">
                  <div className="mb-2">
                    <span className="font-medium">Tech:</span> {p.tags.join(', ')}
                  </div>
                  <div className="flex items-center gap-2">
                    <a href={p.link} className="px-3 py-1.5 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Live</a>
                    <a href="#" className="px-3 py-1.5 rounded-lg border border-gray-200 dark:border-gray-700 hover:bg-gray-100 dark:hover:bg-gray-800 transition">Source</a>
                  </div>
                </div>
              )}

              <div className="mt-4 flex items-center gap-2">
                <button onClick={() => setExpanded(expanded === p.id ? null : p.id)} className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition dark:bg-white dark:text-gray-900 dark:hover:bg-gray-100">
                  {expanded === p.id ? 'Hide details' : 'View details'}
                </button>
                <a href={p.link} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Preview</a>
              </div>
            </div>
          </article>
        ))}
      </div>

      {filtered.length === 0 && (
        <div className="text-center py-12 text-gray-600 dark:text-gray-400">
          No projects found. Try adjusting filters.
        </div>
      )}
    </div>
  )
}

export default ProjectList

