import React, { useEffect, useState } from 'react'

type FormState = {
  name: string
  email: string
  message: string
}

const initial: FormState = { name: '', email: '', message: '' }

const ContactForm: React.FC = () => {
  const [form, setForm] = useState<FormState>(initial)
  const [loading, setLoading] = useState(false)
  const [success, setSuccess] = useState<string | null>(null)
  const [errors, setErrors] = useState<Partial<FormState>>({})

  useEffect(() => {
    setErrors({})
  }, [form.name, form.email, form.message])

  const validate = (): boolean => {
    const e: Partial<FormState> = {}
    if (!form.name.trim()) e.name = 'Please enter your name'
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) e.email = 'Enter a valid email'
    if (form.message.trim().length < 10) e.message = 'Message should be at least 10 characters'
    setErrors(e)
    return Object.keys(e).length === 0
  }

  const onSubmit = async (ev: React.FormEvent) => {
    ev.preventDefault()
    if (!validate()) return
    setLoading(true)
    setSuccess(null)
    await new Promise((r) => setTimeout(r, 900))
    setLoading(false)
    setSuccess('Thanks! Your message has been sent. I will get back to you shortly.')
    setForm(initial)
  }

  const copyEmail = () => {
    navigator.clipboard.writeText('hello@shubham.dev')
      .then(() => setSuccess('Email copied: hello@shubham.dev'))
      .catch(() => setSuccess('Could not copy email, please try again.'))
  }

  return (
    <form onSubmit={onSubmit} className="rounded-xl border border-gray-200 dark:border-gray-700 p-6 shadow-md bg-white dark:bg-gray-900">
      <div className="grid md:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium mb-1">Name</label>
          <input
            value={form.name}
            onChange={(e) => setForm({ ...form, name: e.target.value })}
            placeholder="Your name"
            className={`w-full px-4 py-2.5 rounded-lg border outline-none bg-white dark:bg-gray-900 ${errors.name ? 'border-red-400' : 'border-gray-200 dark:border-gray-700 focus:ring-2 focus:ring-blue-500'}`}
          />
          {errors.name && <div className="text-red-600 text-sm mt-1">{errors.name}</div>}
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Email</label>
          <input
            type="email"
            value={form.email}
            onChange={(e) => setForm({ ...form, email: e.target.value })}
            placeholder="you@example.com"
            className={`w-full px-4 py-2.5 rounded-lg border outline-none bg-white dark:bg-gray-900 ${errors.email ? 'border-red-400' : 'border-gray-200 dark:border-gray-700 focus:ring-2 focus:ring-blue-500'}`}
          />
          {errors.email && <div className="text-red-600 text-sm mt-1">{errors.email}</div>}
        </div>
      </div>
      <div className="mt-4">
        <label className="block text-sm font-medium mb-1">Message</label>
        <textarea
          rows={5}
          value={form.message}
          onChange={(e) => setForm({ ...form, message: e.target.value })}
          placeholder="Tell me a bit about your project, timelines, and goals..."
          className={`w-full px-4 py-2.5 rounded-lg border outline-none bg-white dark:bg-gray-900 ${errors.message ? 'border-red-400' : 'border-gray-200 dark:border-gray-700 focus:ring-2 focus:ring-blue-500'}`}
        />
        {errors.message && <div className="text-red-600 text-sm mt-1">{errors.message}</div>}
      </div>

      <div className="mt-6 flex flex-wrap items-center gap-3">
        <button type="submit" disabled={loading} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition disabled:opacity-60 disabled:cursor-not-allowed">
          {loading ? 'Sending…' : 'Send Message'}
        </button>
        <button type="button" onClick={copyEmail} className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition dark:bg-white dark:text-gray-900 dark:hover:bg-gray-100">Copy Email</button>
        <a href="mailto:hello@shubham.dev" className="px-4 py-2 rounded-lg border border-gray-200 dark:border-gray-700 hover:bg-gray-100 dark:hover:bg-gray-800 transition">Open Mail</a>
      </div>

      {success && (
        <div className="mt-4 p-3 rounded-lg bg-green-50 text-green-700 border border-green-200">{success}</div>
      )}
    </form>
  )
}

export default ContactForm

